AND P.ACTIVITY = 1
AND 1 = 0 AND P.ITEM_TYPE = #{itemTypeSearch, jdbcType=NUMERIC}
AND (P.PARAM_ITEM_ID LIKE '%' || #{itemNameSearch, jdbcType=VARCHAR} || '%' OR SY2.CONTENT LIKE '%' || #{itemNameSearch, jdbcType=VARCHAR} || '%')

mapper.select:
SELECT COUNT(1) FROM ( SELECT P.PARAM_ITEM_NO FROM PA_PARAM_ITEM P, SY_GLOBAL_NAME SY2 WHERE P.PARAM_ITEM_NO = SY2.NO(+) AND SY2.LANGUAGE(+) = #{lang, jdbcType=VARCHAR}
UNION ALL SELECT PA.ITEM_NO FROM PA_ITEM PA, SY_GLOBAL_NAME SY3 WHERE PA.ITEM_NO = SY3.NO(+) AND SY3.LANGUAGE(+) = #{lang, jdbcType=VARCHAR}
)

SELECT ITEM_TYPE, ITEM_NO, ITEM_ID, MAP_CODE, ITEM_NAME, DATA_TYPE, DESCR, CREATED_BY, CREATE_DATE, ACTIVITY, COMPANY_USAGE_STR FROM ( SELECT a.*, ROWNUM AS RN FROM ( SELECT P.ITEM_TYPE, P.PARAM_ITEM_NO AS ITEM_NO, P.PARAM_ITEM_ID AS ITEM_ID, P.MAP_CODE, SY2.CONTENT AS ITEM_NAME, P.DATA_TYPE, P.DESCR, get_emp_local_name(P.CREATED_BY, #{cpnyId, jdbcType=VARCHAR}) || ' ' || P.CREATED_IP AS CREATED_BY, TO_CHAR(P.CREATE_DATE, 'YYYY-MM-DD HH24:MI') AS CREATE_DATE, P.ACTIVITY, (SELECT LISTAGG(PP.CPNY_ID, ', ') WITHIN GROUP (ORDER BY PP.ORDERNO) FROM PA_PARAM_ITEM_PARAM PP WHERE PP.PARAM_ITEM_NO = P.PARAM_ITEM_NO AND PP.ACTIVITY = 1) AS COMPANY_USAGE_STR FROM PA_PARAM_ITEM P, SY_GLOBAL_NAME SY2 WHERE P.PARAM_ITEM_NO = SY2.NO(+) AND SY2.LANGUAGE(+) = #{lang, jdbcType=VARCHAR}
UNION ALL SELECT 6 AS ITEM_TYPE, PA.ITEM_NO, PA.ITEM_ID, PA.MAP_CODE, SY3.CONTENT AS ITEM_NAME, PA.DATATYPE AS DATA_TYPE, PA.DESCR, get_emp_local_name(PA.CREATED_BY, #{cpnyId, jdbcType=VARCHAR}) || ' ' || PA.CREATED_IP AS CREATED_BY, TO_CHAR(PA.CREATE_DATE, 'YYYY-MM-DD HH24:MI') AS CREATE_DATE, PA.ACTIVITY, (SELECT LISTAGG(IP.CPNY_ID, ', ') WITHIN GROUP (ORDER BY IP.ORDERNO) FROM PA_ITEM_PARAM IP WHERE IP.ITEM_NO = PA.ITEM_NO AND IP.ACTIVITY = 1) AS COMPANY_USAGE_STR FROM PA_ITEM PA, SY_GLOBAL_NAME SY3 WHERE PA.ITEM_NO = SY3.NO(+) AND SY3.LANGUAGE(+) = #{lang, jdbcType=VARCHAR}
ORDER BY ITEM_TYPE, ITEM_ID ) a WHERE ROWNUM <= #{start, jdbcType=NUMERIC} + #{length, jdbcType=NUMERIC} ) WHERE RN > #{start, jdbcType=NUMERIC}
